// ── seedAssemblyLibrary ────────────────────────────────────
export async function seedAssemblyLibrary(
  prisma: any,
  costDatabaseId: string,
): Promise<number> {
  let seeded = 0;
  const categories = new Map<string, number>();

  for (const a of MARKETPLACE_ASSEMBLIES) {
    const unitCost = a.materialCostMid + a.laborCostMid;

    await prisma.assembly.upsert({
      where: { code: a.code },
      update: {
        name: a.name,
        description: a.description ?? null,
        category: a.category,
        subcategory: a.subcategory ?? null,
        unit: a.unit,
        materialCost: a.materialCostMid,
        laborCost: a.laborCostMid,
        unitCost,
        laborHours: a.laborHoursPerUnit ?? 0,
        materialCostLow: a.materialCostLow,
        materialCostMid: a.materialCostMid,
        materialCostHigh: a.materialCostHigh,
        laborCostLow: a.laborCostLow,
        laborCostMid: a.laborCostMid,
        laborCostHigh: a.laborCostHigh,
        laborHoursPerUnit: a.laborHoursPerUnit ?? null,
        regionMultiplier: a.regionMultiplier,
        tradesRequired: a.tradesRequired,
        complexity: a.complexity,
        tags: a.tags,
        isTemplate: true,
        isActive: true,
        costDatabaseId,
      },
      create: {
        code: a.code,
        name: a.name,
        description: a.description ?? null,
        category: a.category,
        subcategory: a.subcategory ?? null,
        unit: a.unit,
        materialCost: a.materialCostMid,
        laborCost: a.laborCostMid,
        unitCost,
        laborHours: a.laborHoursPerUnit ?? 0,
        materialCostLow: a.materialCostLow,
        materialCostMid: a.materialCostMid,
        materialCostHigh: a.materialCostHigh,
        laborCostLow: a.laborCostLow,
        laborCostMid: a.laborCostMid,
        laborCostHigh: a.laborCostHigh,
        laborHoursPerUnit: a.laborHoursPerUnit ?? null,
        regionMultiplier: a.regionMultiplier,
        tradesRequired: a.tradesRequired,
        complexity: a.complexity,
        tags: a.tags,
        isTemplate: true,
        isActive: true,
        costDatabaseId,
      },
    });

    seeded++;
    const cat = a.category;
    categories.set(cat, (categories.get(cat) ?? 0) + 1);
  }

  console.log("\n=== Assembly Seed Summary ===");
  for (const [cat, count] of [...categories.entries()].sort()) {
    console.log(`  ${cat}: ${count} assemblies`);
  }
  console.log(`  TOTAL: ${seeded} assemblies seeded.\n`);

  return seeded;
}
